import React from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import Layout from './components/layout/Layout';
import Dashboard from './components/dashboard/Dashboard';
import PolicyInquiry from './components/policy/PolicyInquiry';
import RegistrasiPayor from './components/policy/RegistrasiPayor';
import RegistrasiPlan from './components/policy/RegistrasiPlan';
import RegistrasiParticipant from './components/policy/RegistrasiParticipant';
import ClaimInquiry from './components/claim/ClaimInquiry';
import Summary from './components/claim/Summary';
import HistoryClaim from './components/claim/HistoryClaim';
import Report from './components/report/Report';
import './styles/App.css';

function App() {
  return (
    <Router>
      <Layout>
        <Routes>
          {/* Menu Utama */}
          <Route path="/" element={<Dashboard />} />
          <Route path="/dashboard" element={<Dashboard />} />
          <Route path="/policy" element={<PolicyInquiry />} />
          <Route path="/claim" element={<ClaimInquiry />} />
          <Route path="/report" element={<Report />} />

          {/* Sub Menu Policy */}
          <Route path="/policy/payor" element={<RegistrasiPayor />} />
          <Route path="/policy/plan" element={<RegistrasiPlan />} />
          <Route path="/policy/participant" element={<RegistrasiParticipant />} />

          {/* Sub Menu Claim */}
          <Route path="/claim/summary" element={<Summary />} />
          <Route path="/claim/history" element={<HistoryClaim />} />
        </Routes>
      </Layout>
    </Router>
  );
}

export default App;
